77	// FirstUsernetIndex gets the index of first usernet network under l.Network[]. Returns -1 if no usernet network found.
78	func FirstUsernetIndex(l *limatype.LimaYAML) int {
79		return slices.IndexFunc(l.Networks, func(network limatype.Network) bool { return networks.IsUsernet(network.Lima) })
80	}
81	
82	func MACAddress(uniqueID string) string {
83		sha := sha256.Sum256([]byte(osutil.MachineID() + uniqueID))
84		// "5" is the magic number in the Lima ecosystem.
85		// (Visit https://en.wiktionary.org/wiki/lima and Command-F "five")
86		//
87		// But the second hex number is changed to 2 to satisfy the convention for
88		// local MAC addresses (https://en.wikipedia.org/wiki/MAC_address#Ranges_of_group_and_locally_administered_addresses)
89		//
90		// See also https://gitlab.com/wireshark/wireshark/-/blob/release-4.0/manuf to confirm the uniqueness of this prefix.
91		hw := append(net.HardwareAddr{0x52, 0x55, 0x55}, sha[0:3]...)
92		return hw.String()
93	}
94	
95	// MountTag generates a stable mount tag from location and mountPoint.
96	// Both paths are hashed to handle the same location mounted to multiple mount points.
97	func MountTag(location, mountPoint string) string {
98		sha := sha256.Sum256([]byte(location + "\x00" + mountPoint))
99		return fmt.Sprintf("lima-%x", sha[0:8])
100	}
101	
102	func defaultCPUs() int {
103		const x = 4
104		if hostCPUs := runtime.NumCPU(); hostCPUs < x {
105			return hostCPUs
106		}
107		return x
108	}
109	
110	func defaultMemory() uint64 {
111		const x uint64 = 4 * 1024 * 1024 * 1024
112		if halfOfHostMemory := memory.TotalMemory() / 2; halfOfHostMemory < x {
113			return halfOfHostMemory
114		}
115		return x
116	}
117	
118	func defaultMemoryAsString() string {
119		return units.BytesSize(float64(defaultMemory()))
120	}
121	
122	func defaultDiskSizeAsString() string {
123		// currently just hardcoded
124		return "100GiB"
