131	// FillDefault updates undefined fields in y with defaults from d (or built-in default), and overwrites with values from o.
132	// Both d and o may be empty.
133	//
134	// Maps (`Env`) are being merged: first populated from d, overwritten by y, and again overwritten by o.
135	// Slices (e.g. `Mounts`, `Provision`) are appended, starting with o, followed by y, and finally d. This
136	// makes sure o takes priority over y over d, in cases it matters (e.g. `PortForwards`, where the first
137	// matching rule terminates the search).
138	//
139	// Exceptions:
140	//   - Mounts are appended in d, y, o order, but "merged" when the Location matches a previous entry;
141	//     the highest priority Writable setting wins.
142	//   - Networks are appended in d, y, o order
143	//   - DNS are picked from the highest priority where DNS is not empty.
144	//   - CACertificates Files and Certs are uniquely appended in d, y, o order
145	func FillDefault(ctx context.Context, y, d, o *limatype.LimaYAML, filePath string, warn bool) {
146		instDir := filepath.Dir(filePath)
147	
148		existingLimaVersion := ExistingLimaVersion(instDir)
149	
150		// OS has to be resolved before User
151		if y.OS == nil {
152			y.OS = d.OS
153		}
154		if o.OS != nil {
155			y.OS = o.OS
156		}
157		y.OS = ptr.Of(ResolveOS(y.OS))
158	
159		if y.User.Name == nil {
160			y.User.Name = d.User.Name
161		}
162		if y.User.Comment == nil {
163			y.User.Comment = d.User.Comment
164		}
165		if y.User.Home == nil {
166			y.User.Home = d.User.Home
167		}
168		if y.User.Shell == nil {
169			y.User.Shell = d.User.Shell
170		}
171		if y.User.UID == nil {
172			y.User.UID = d.User.UID
173		}
174		if o.User.Name != nil {
175			y.User.Name = o.User.Name
176		}
177		if o.User.Comment != nil {
178			y.User.Comment = o.User.Comment
179		}
180		if o.User.Home != nil {
181			y.User.Home = o.User.Home
182		}
183		if o.User.Shell != nil {
184			y.User.Shell = o.User.Shell
185		}
186		if o.User.UID != nil {
187			y.User.UID = o.User.UID
188		}
189		if y.User.Name == nil {
190			y.User.Name = ptr.Of(osutil.LimaUser(ctx, existingLimaVersion, warn, y.OS).Username)
191			warn = false
192		}
193		if y.User.Comment == nil {
194			y.User.Comment = ptr.Of(osutil.LimaUser(ctx, existingLimaVersion, warn, y.OS).Name)
195			warn = false
196		}
197		if y.User.Home == nil {
198			y.User.Home = ptr.Of(osutil.LimaUser(ctx, existingLimaVersion, warn, y.OS).HomeDir)
199			warn = false
200		}
201		if y.User.Shell == nil {
202			switch *y.OS {
203			case limatype.FREEBSD:
204				y.User.Shell = ptr.Of("/bin/sh")
205			case limatype.DARWIN:
206				y.User.Shell = ptr.Of("/bin/zsh")
207			default:
208				y.User.Shell = ptr.Of("/bin/bash")
209			}
210		}
211		if y.User.UID == nil {
212			uidString := osutil.LimaUser(ctx, existingLimaVersion, warn, y.OS).Uid
213			if uid, err := strconv.ParseUint(uidString, 10, 32); err == nil {
214				y.User.UID = ptr.Of(uint32(uid))
215			} else {
216				// This should never happen; LimaUser() makes sure that .Uid is numeric
217				logrus.WithError(err).Warnf("Can't parse `user.uid` %q", uidString)
218				y.User.UID = ptr.Of(uint32(1000))
219			}
220			// warn = false
221		}
222		if out, err := executeGuestTemplate(*y.User.Home, instDir, y.User, y.Param); err == nil {
223			y.User.Home = ptr.Of(out.String())
224		} else {
225			logrus.WithError(err).Warnf("Couldn't process `user.home` value %q as a template", *y.User.Home)
226		}
227	
228		if y.VMType == nil {
229			y.VMType = d.VMType
230		}
231		if o.VMType != nil {
232			y.VMType = o.VMType
233		}
234	
235		if y.Arch == nil {
236			y.Arch = d.Arch
237		}
238		if o.Arch != nil {
239			y.Arch = o.Arch
240		}
241		y.Arch = ptr.Of(ResolveArch(y.Arch))
242	
243		y.Images = slices.Concat(o.Images, y.Images, d.Images)
244		for i := range y.Images {
245			img := &y.Images[i]
246			if img.Arch == "" {
247				img.Arch = *y.Arch
248			}
249			if img.Kernel != nil && img.Kernel.Arch == "" {
250				img.Kernel.Arch = img.Arch
251			}
252			if img.Initrd != nil && img.Initrd.Arch == "" {
253				img.Initrd.Arch = img.Arch
254			}
255		}
256	
257		if y.CPUs == nil {
258			y.CPUs = d.CPUs
259		}
260		if o.CPUs != nil {
261			y.CPUs = o.CPUs
262		}
263		if y.CPUs == nil || *y.CPUs == 0 {
264			y.CPUs = ptr.Of(defaultCPUs())
265		}
266	
267		if y.Memory == nil {
268			y.Memory = d.Memory
269		}
270		if o.Memory != nil {
271			y.Memory = o.Memory
272		}
273		if y.Memory == nil || *y.Memory == "" {
274			y.Memory = ptr.Of(defaultMemoryAsString())
275		}
276	
277		if y.Disk == nil {
278			y.Disk = d.Disk
279		}
280		if o.Disk != nil {
281			y.Disk = o.Disk
282		}
283		if y.Disk == nil || *y.Disk == "" {
284			y.Disk = ptr.Of(defaultDiskSizeAsString())
285		}
286	
287		y.AdditionalDisks = slices.Concat(o.AdditionalDisks, y.AdditionalDisks, d.AdditionalDisks)
288	
289		if y.Audio.Device == nil {
290			y.Audio.Device = d.Audio.Device
291		}
292		if o.Audio.Device != nil {
293			y.Audio.Device = o.Audio.Device
294		}
295		if y.Audio.Device == nil {
296			y.Audio.Device = ptr.Of("")
297		}
298	
299		if y.Video.Display == nil {
300			y.Video.Display = d.Video.Display
301		}
302		if o.Video.Display != nil {
303			y.Video.Display = o.Video.Display
304		}
305		if y.Video.Display == nil || *y.Video.Display == "" {
306			y.Video.Display = ptr.Of("none")
307		}
308	
309		if y.Video.VNC.Display == nil {
310			y.Video.VNC.Display = d.Video.VNC.Display
311		}
312		if o.Video.VNC.Display != nil {
313			y.Video.VNC.Display = o.Video.VNC.Display
314		}
315	
316		if y.Firmware.LegacyBIOS == nil {
317			y.Firmware.LegacyBIOS = d.Firmware.LegacyBIOS
318		}
319		if o.Firmware.LegacyBIOS != nil {
320			y.Firmware.LegacyBIOS = o.Firmware.LegacyBIOS
321		}
322		if y.Firmware.LegacyBIOS == nil {
323			y.Firmware.LegacyBIOS = ptr.Of(false)
324		}
325	
326		y.Firmware.Images = slices.Concat(o.Firmware.Images, y.Firmware.Images, d.Firmware.Images)
327		for i := range y.Firmware.Images {
328			f := &y.Firmware.Images[i]
329			if f.Arch == "" {
330				f.Arch = *y.Arch
331			}
332		}
333	
334		if y.TimeZone == nil {
335			y.TimeZone = d.TimeZone
336		}
337		if o.TimeZone != nil {
338			y.TimeZone = o.TimeZone
339		}
340		if y.TimeZone == nil {
341			y.TimeZone = ptr.Of(hostTimeZone())
342		}
343	
344		if y.SSH.LocalPort == nil {
345			y.SSH.LocalPort = d.SSH.LocalPort
346		}
347		if o.SSH.LocalPort != nil {
348			y.SSH.LocalPort = o.SSH.LocalPort
349		}
350		if y.SSH.LocalPort == nil {
351			// y.SSH.LocalPort value is not filled here (filled by the hostagent)
352			y.SSH.LocalPort = ptr.Of(0)
353		}
354		if y.SSH.LoadDotSSHPubKeys == nil {
355			y.SSH.LoadDotSSHPubKeys = d.SSH.LoadDotSSHPubKeys
356		}
357		if o.SSH.LoadDotSSHPubKeys != nil {
358			y.SSH.LoadDotSSHPubKeys = o.SSH.LoadDotSSHPubKeys
359		}
360		if y.SSH.LoadDotSSHPubKeys == nil {
361			y.SSH.LoadDotSSHPubKeys = ptr.Of(false) // was true before Lima v1.0
362		}
363	
364		if y.SSH.ForwardAgent == nil {
365			y.SSH.ForwardAgent = d.SSH.ForwardAgent
366		}
367		if o.SSH.ForwardAgent != nil {
368			y.SSH.ForwardAgent = o.SSH.ForwardAgent
369		}
370		if y.SSH.ForwardAgent == nil {
371			y.SSH.ForwardAgent = ptr.Of(false)
372		}
373	
374		if y.SSH.ForwardX11 == nil {
375			y.SSH.ForwardX11 = d.SSH.ForwardX11
376		}
377		if o.SSH.ForwardX11 != nil {
378			y.SSH.ForwardX11 = o.SSH.ForwardX11
379		}
380		if y.SSH.ForwardX11 == nil {
381			y.SSH.ForwardX11 = ptr.Of(false)
382		}
383	
384		if y.SSH.ForwardX11Trusted == nil {
385			y.SSH.ForwardX11Trusted = d.SSH.ForwardX11Trusted
386		}
387		if o.SSH.ForwardX11Trusted != nil {
388			y.SSH.ForwardX11Trusted = o.SSH.ForwardX11Trusted
389		}
390		if y.SSH.ForwardX11Trusted == nil {
391			y.SSH.ForwardX11Trusted = ptr.Of(false)
392		}
393	
394		if y.SSH.OverVsock == nil {
395			y.SSH.OverVsock = d.SSH.OverVsock
396		}
397		if o.SSH.OverVsock != nil {
398			y.SSH.OverVsock = o.SSH.OverVsock
399		}
400		// y.SSH.OverVsock default value depends on the driver; filled in driver-specific FillDefault()
401	
402		// The deprecated environment variable LIMA_SSH_OVER_VSOCK takes precedence over .ssh.overVsock
403		if envVar := os.Getenv("LIMA_SSH_OVER_VSOCK"); envVar != "" {
404			logrus.Warn("The environment variable LIMA_SSH_OVER_VSOCK is deprecated in favor of the YAML field .ssh.overVsock")
405			b, err := strconv.ParseBool(envVar)
406			if err != nil {
407				logrus.WithError(err).Warnf("invalid LIMA_SSH_OVER_VSOCK value %q", envVar)
408			} else {
409				logrus.Debugf("Overriding ssh.overVsock from %v to %v via LIMA_SSH_OVER_VSOCK", y.SSH.OverVsock, &b)
410				y.SSH.OverVsock = ptr.Of(b)
411			}
412		}
413	
414		hosts := make(map[string]string)
415		// Values can be either names or IP addresses. Name values are canonicalized in the hostResolver.
416		maps.Copy(hosts, d.HostResolver.Hosts)
417		maps.Copy(hosts, y.HostResolver.Hosts)
418		maps.Copy(hosts, o.HostResolver.Hosts)
419		y.HostResolver.Hosts = hosts
420	
421		y.Provision = slices.Concat(o.Provision, y.Provision, d.Provision)
422		for i := range y.Provision {
423			provision := &y.Provision[i]
424			if provision.Mode == "" {
425				provision.Mode = limatype.ProvisionModeSystem
426			}
427			if provision.Mode == limatype.ProvisionModeDependency && provision.SkipDefaultDependencyResolution == nil {
428				provision.SkipDefaultDependencyResolution = ptr.Of(false)
429			}
430			if provision.Mode == limatype.ProvisionModeData {
431				if provision.Content == nil {
432					provision.Content = ptr.Of("")
433				} else {
434					if out, err := executeGuestTemplate(*provision.Content, instDir, y.User, y.Param); err == nil {
435						provision.Content = ptr.Of(out.String())
436					} else {
437						logrus.WithError(err).Warnf("Couldn't process data content %q as a template", *provision.Content)
438					}
439				}
440				if provision.Overwrite == nil {
441					provision.Overwrite = ptr.Of(true)
442				}
443			}
444			if provision.Mode == limatype.ProvisionModeYQ {
445				if provision.Expression != nil {
446					if out, err := executeGuestTemplate(*provision.Expression, instDir, y.User, y.Param); err == nil {
447						provision.Expression = ptr.Of(out.String())
448					} else {
449						logrus.WithError(err).Warnf("Couldn't process expression %q as a template", *provision.Expression)
450					}
451				}
452				if provision.Format == nil {
453					provision.Format = ptr.Of("auto")
454				}
455			}
456			if provision.Mode == limatype.ProvisionModeData || provision.Mode == limatype.ProvisionModeYQ {
457				if provision.Owner == nil {
458					switch *y.OS {
459					case limatype.DARWIN, limatype.FREEBSD:
460						provision.Owner = ptr.Of("root:wheel")
461					default:
462						provision.Owner = ptr.Of("root:root")
463					}
464				} else {
465					if out, err := executeGuestTemplate(*provision.Owner, instDir, y.User, y.Param); err == nil {
466						provision.Owner = ptr.Of(out.String())
467					} else {
468						logrus.WithError(err).Warnf("Couldn't process owner %q as a template", *provision.Owner)
469					}
470				}
471				// Path is required; validation will throw an error when it is nil
472				if provision.Path != nil {
473					if out, err := executeGuestTemplate(*provision.Path, instDir, y.User, y.Param); err == nil {
474						provision.Path = ptr.Of(out.String())
475					} else {
476						logrus.WithError(err).Warnf("Couldn't process path %q as a template", *provision.Path)
477					}
478				}
479				if provision.Permissions == nil {
480					provision.Permissions = ptr.Of("644")
481				}
482			}
483			if provision.Script == nil {
484				provision.Script = ptr.Of("")
485			}
486			if *provision.Script != "" {
487				if out, err := executeGuestTemplate(*provision.Script, instDir, y.User, y.Param); err == nil {
488					*provision.Script = out.String()
489				} else {
490					logrus.WithError(err).Warnf("Couldn't process provisioning script %q as a template", *provision.Script)
491				}
492			}
493		}
494	
495		if y.GuestInstallPrefix == nil {
496			y.GuestInstallPrefix = d.GuestInstallPrefix
497		}
498		if o.GuestInstallPrefix != nil {
499			y.GuestInstallPrefix = o.GuestInstallPrefix
500		}
501		if y.GuestInstallPrefix == nil {
502			y.GuestInstallPrefix = ptr.Of(defaultGuestInstallPrefix())
503		}
504	
505		if y.UpgradePackages == nil {
506			y.UpgradePackages = d.UpgradePackages
507		}
508		if o.UpgradePackages != nil {
509			y.UpgradePackages = o.UpgradePackages
510		}
511		if y.UpgradePackages == nil {
512			y.UpgradePackages = ptr.Of(false)
513		}
514	
515		if y.Containerd.System == nil {
516			y.Containerd.System = d.Containerd.System
517		}
518		if o.Containerd.System != nil {
519			y.Containerd.System = o.Containerd.System
520		}
521		if y.Containerd.System == nil {
522			y.Containerd.System = ptr.Of(false)
523		}
524		if y.Containerd.User == nil {
525			y.Containerd.User = d.Containerd.User
526		}
527		if o.Containerd.User != nil {
528			y.Containerd.User = o.Containerd.User
529		}
530		if y.Containerd.User == nil {
531			switch *y.Arch {
532			case limatype.X8664, limatype.AARCH64:
533				y.Containerd.User = ptr.Of(true)
534			default:
535				y.Containerd.User = ptr.Of(false)
536			}
537		}
538	
539		y.Containerd.Archives = slices.Concat(o.Containerd.Archives, y.Containerd.Archives, d.Containerd.Archives)
540		if len(y.Containerd.Archives) == 0 {
541			y.Containerd.Archives = defaultContainerdArchives()
542		}
543		for i := range y.Containerd.Archives {
544			f := &y.Containerd.Archives[i]
545			if f.Arch == "" {
546				f.Arch = *y.Arch
547			}
548		}
549	
550		y.Probes = slices.Concat(o.Probes, y.Probes, d.Probes)
551		for i := range y.Probes {
552			probe := &y.Probes[i]
553			if probe.Mode == "" {
554				probe.Mode = limatype.ProbeModeReadiness
555			}
556			if probe.Description == "" {
557				probe.Description = fmt.Sprintf("user probe %d/%d", i+1, len(y.Probes))
558			}
559			if probe.Script == nil {
560				probe.Script = ptr.Of("")
561			}
562			if out, err := executeGuestTemplate(*probe.Script, instDir, y.User, y.Param); err == nil {
563				probe.Script = ptr.Of(out.String())
564			} else {
565				logrus.WithError(err).Warnf("Couldn't process probing script %q as a template", *probe.Script)
566			}
567		}
568	
569		y.PortForwards = slices.Concat(o.PortForwards, y.PortForwards, d.PortForwards)
570		for i := range y.PortForwards {
571			FillPortForwardDefaults(&y.PortForwards[i], instDir, y.User, y.Param)
572			// After defaults processing the singular HostPort and GuestPort values should not be used again.
573		}
574	
575		y.CopyToHost = slices.Concat(o.CopyToHost, y.CopyToHost, d.CopyToHost)
576		for i := range y.CopyToHost {
577			FillCopyToHostDefaults(&y.CopyToHost[i], instDir, y.User, y.Param)
578		}
579	
580		if y.HostResolver.Enabled == nil {
581			y.HostResolver.Enabled = d.HostResolver.Enabled
582		}
583		if o.HostResolver.Enabled != nil {
584			y.HostResolver.Enabled = o.HostResolver.Enabled
585		}
586		if y.HostResolver.Enabled == nil {
587			y.HostResolver.Enabled = ptr.Of(true)
588		}
589	
590		if y.HostResolver.IPv6 == nil {
591			y.HostResolver.IPv6 = d.HostResolver.IPv6
592		}
593		if o.HostResolver.IPv6 != nil {
594			y.HostResolver.IPv6 = o.HostResolver.IPv6
595		}
596		if y.HostResolver.IPv6 == nil {
597			y.HostResolver.IPv6 = ptr.Of(false)
598		}
599	
600		if y.PropagateProxyEnv == nil {
601			y.PropagateProxyEnv = d.PropagateProxyEnv
602		}
603		if o.PropagateProxyEnv != nil {
604			y.PropagateProxyEnv = o.PropagateProxyEnv
605		}
606		if y.PropagateProxyEnv == nil {
607			y.PropagateProxyEnv = ptr.Of(true)
608		}
609	
610		networks := make([]limatype.Network, 0, len(d.Networks)+len(y.Networks)+len(o.Networks))
611		iface := make(map[string]int)
612		for _, nw := range slices.Concat(d.Networks, y.Networks, o.Networks) {
613			if i, ok := iface[nw.Interface]; ok {
614				if nw.Socket != "" {
615					networks[i].Socket = nw.Socket
616					networks[i].Lima = ""
617				}
618				if nw.Lima != "" {
619					if nw.Socket != "" {
620						// We can't return an error, so just log it, and prefer `lima` over `socket`
621						logrus.Errorf("Network %q has both socket=%q and lima=%q fields; ignoring socket",
622							nw.Interface, nw.Socket, nw.Lima)
623					}
624					networks[i].Lima = nw.Lima
625					networks[i].Socket = ""
626				}
627				if nw.MACAddress != "" {
628					networks[i].MACAddress = nw.MACAddress
629				}
630				if nw.Metric != nil {
631					networks[i].Metric = nw.Metric
632				}
633			} else {
634				// unnamed network definitions are not combined/overwritten
635				if nw.Interface != "" {
636					iface[nw.Interface] = len(networks)
637				}
638				networks = append(networks, nw)
639			}
640		}
641		y.Networks = networks
642		for i := range y.Networks {
643			nw := &y.Networks[i]
644			if nw.MACAddress == "" {
645				// every interface in every limayaml file must get its own unique MAC address
646				nw.MACAddress = MACAddress(fmt.Sprintf("%s#%d", filePath, i))
647			}
648			if nw.Interface == "" {
649				nw.Interface = "lima" + strconv.Itoa(i)
650			}
651			if nw.Metric == nil {
652				nw.Metric = ptr.Of(uint32(100))
653			}
654		}
655	
656		y.MountTypesUnsupported = slices.Concat(o.MountTypesUnsupported, y.MountTypesUnsupported, d.MountTypesUnsupported)
657	
658		// MountType has to be resolved before resolving Mounts
659		if y.MountType == nil {
660			y.MountType = d.MountType
661		}
662		if o.MountType != nil {
663			y.MountType = o.MountType
664		}
665	
666		if y.MountInotify == nil {
667			y.MountInotify = d.MountInotify
668		}
669		if o.MountInotify != nil {
670			y.MountInotify = o.MountInotify
671		}
672		if y.MountInotify == nil {
673			y.MountInotify = ptr.Of(false)
674		}
675	
676		// Combine all mounts; highest priority entry determines writable status.
677		// Only works for exact matches; does not normalize case or resolve symlinks.
678		mounts := make([]limatype.Mount, 0, len(d.Mounts)+len(y.Mounts)+len(o.Mounts))
679		mountPoint := make(map[string]int)
680		for _, mount := range slices.Concat(d.Mounts, y.Mounts, o.Mounts) {
681			if out, err := executeHostTemplate(mount.Location, instDir, y.Param); err == nil {
682				mount.Location = filepath.Clean(out.String())
683			} else {
684				logrus.WithError(err).Warnf("Couldn't process mount location %q as a template", mount.Location)
685			}
686			// Expand a path that begins with `~`. Relative paths are not modified, and rejected by Validate() later.
687			if localpathutil.IsTildePath(mount.Location) {
688				if location, err := localpathutil.Expand(mount.Location); err == nil {
689					mount.Location = location
690				} else {
691					logrus.WithError(err).Warnf("Couldn't expand location %q", mount.Location)
692				}
693			}
694			if mount.MountPoint == nil {
695				mountLocation := mount.Location
696				if runtime.GOOS == "windows" {
697					var err error
698					mountLocation, err = ioutilx.WindowsSubsystemPath(ctx, mountLocation)
699					if err != nil {
700						logrus.WithError(err).Warnf("Couldn't convert location %q into mount target", mount.Location)
701					}
702				}
703				mount.MountPoint = ptr.Of(mountLocation)
704			} else {
705				if out, err := executeGuestTemplate(*mount.MountPoint, instDir, y.User, y.Param); err == nil {
706					mount.MountPoint = ptr.Of(out.String())
707				} else {
708					logrus.WithError(err).Warnf("Couldn't process mount point %q as a template", *mount.MountPoint)
709				}
710			}
711			if i, ok := mountPoint[*mount.MountPoint]; ok {
712				if mount.SSHFS.Cache != nil {
713					mounts[i].SSHFS.Cache = mount.SSHFS.Cache
714				}
715				if mount.SSHFS.FollowSymlinks != nil {
716					mounts[i].SSHFS.FollowSymlinks = mount.SSHFS.FollowSymlinks
717				}
718				if mount.SSHFS.SFTPDriver != nil {
719					mounts[i].SSHFS.SFTPDriver = mount.SSHFS.SFTPDriver
720				}
721				if mount.NineP.SecurityModel != nil {
722					mounts[i].NineP.SecurityModel = mount.NineP.SecurityModel
723				}
724				if mount.NineP.ProtocolVersion != nil {
725					mounts[i].NineP.ProtocolVersion = mount.NineP.ProtocolVersion
726				}
727				if mount.NineP.Msize != nil {
728					mounts[i].NineP.Msize = mount.NineP.Msize
729				}
730				if mount.NineP.Cache != nil {
731					mounts[i].NineP.Cache = mount.NineP.Cache
732				}
733				if mount.Virtiofs.QueueSize != nil {
734					mounts[i].Virtiofs.QueueSize = mount.Virtiofs.QueueSize
735				}
736				if mount.Writable != nil {
737					mounts[i].Writable = mount.Writable
738				}
739				if mount.MountPoint != nil {
740					mounts[i].MountPoint = mount.MountPoint
741				}
742			} else {
743				mountPoint[*mount.MountPoint] = len(mounts)
744				mounts = append(mounts, mount)
745			}
746		}
747		y.Mounts = mounts
748	
749		for i := range y.Mounts {
750			mount := &y.Mounts[i]
751			if mount.SSHFS.Cache == nil {
752				mount.SSHFS.Cache = ptr.Of(true)
753			}
754			if mount.SSHFS.FollowSymlinks == nil {
755				mount.SSHFS.FollowSymlinks = ptr.Of(false)
756			}
757			if mount.SSHFS.SFTPDriver == nil {
758				mount.SSHFS.SFTPDriver = ptr.Of("")
759			}
760			if mount.NineP.SecurityModel == nil {
761				mounts[i].NineP.SecurityModel = ptr.Of(Default9pSecurityModel)
762			}
763			if mount.NineP.ProtocolVersion == nil {
764				mounts[i].NineP.ProtocolVersion = ptr.Of(Default9pProtocolVersion)
765			}
766			if mount.NineP.Msize == nil {
767				mounts[i].NineP.Msize = ptr.Of(Default9pMsize)
768			}
769			if mount.Writable == nil {
770				mount.Writable = ptr.Of(false)
771			}
772			if mount.NineP.Cache == nil {
773				if *mount.Writable {
774					mounts[i].NineP.Cache = ptr.Of(Default9pCacheForRW)
775				} else {
776					mounts[i].NineP.Cache = ptr.Of(Default9pCacheForRO)
777				}
778			}
779		}
780	
781		// Note: DNS lists are not combined; highest priority setting is picked
782		if len(y.DNS) == 0 {
783			y.DNS = d.DNS
784		}
785		if len(o.DNS) > 0 {
786			y.DNS = o.DNS
787		}
788	
789		env := make(map[string]string)
790		maps.Copy(env, d.Env)
791		maps.Copy(env, y.Env)
792		maps.Copy(env, o.Env)
793		y.Env = env
794	
795		param := make(map[string]string)
796		maps.Copy(param, d.Param)
797		maps.Copy(param, y.Param)
798		maps.Copy(param, o.Param)
799		y.Param = param
800	
801		vmOpts := make(limatype.VMOpts)
802		maps.Copy(vmOpts, d.VMOpts)
803		maps.Copy(vmOpts, y.VMOpts)
804		maps.Copy(vmOpts, o.VMOpts)
805		y.VMOpts = vmOpts
806	
807		if y.CACertificates.RemoveDefaults == nil {
808			y.CACertificates.RemoveDefaults = d.CACertificates.RemoveDefaults
809		}
810		if o.CACertificates.RemoveDefaults != nil {
811			y.CACertificates.RemoveDefaults = o.CACertificates.RemoveDefaults
812		}
813		if y.CACertificates.RemoveDefaults == nil {
814			y.CACertificates.RemoveDefaults = ptr.Of(false)
815		}
816	
817		y.CACertificates.Files = unique(slices.Concat(d.CACertificates.Files, y.CACertificates.Files, o.CACertificates.Files))
818		y.CACertificates.Certs = unique(slices.Concat(d.CACertificates.Certs, y.CACertificates.Certs, o.CACertificates.Certs))
819	
820		if y.NestedVirtualization == nil {
821			y.NestedVirtualization = d.NestedVirtualization
822		}
823		if o.NestedVirtualization != nil {
824			y.NestedVirtualization = o.NestedVirtualization
825		}
826		if y.NestedVirtualization == nil {
827			y.NestedVirtualization = ptr.Of(false)
828		}
829	
830		if y.Plain == nil {
831			y.Plain = d.Plain
832		}
833		if o.Plain != nil {
834			y.Plain = o.Plain
835		}
836		if y.Plain == nil {
837			y.Plain = ptr.Of(false)
838		}
839	
840		fixUpForPlainMode(y)
841	}
842	
843	// ExistingLimaVersion returns empty if the instance was created with Lima prior to v0.20.
844	func ExistingLimaVersion(instDir string) string {
845		if !IsExistingInstanceDir(instDir) {
846			return version.Version
847		}
848	
849		limaVersionFile := filepath.Join(instDir, filenames.LimaVersion)
850		if b, err := os.ReadFile(limaVersionFile); err == nil {
851			return strings.TrimSpace(string(b))
852		} else if !errors.Is(err, os.ErrNotExist) {
853			logrus.WithError(err).Warnf("Failed to read %q", limaVersionFile)
854		}
855	
856		return version.Version
857	}
858	
859	func fixUpForPlainMode(y *limatype.LimaYAML) {
860		if !*y.Plain {
861			return
862		}
863		deleteNonStaticPortForwards(&y.PortForwards)
864		y.Mounts = nil
865		y.Containerd.System = ptr.Of(false)
866		y.Containerd.User = ptr.Of(false)
867		y.TimeZone = ptr.Of("")
868	}
869	
870	// deleteNonStaticPortForwards removes all non-static port forwarding rules in case of Plain mode.
871	func deleteNonStaticPortForwards(portForwards *[]limatype.PortForward) {
872		staticPortForwards := make([]limatype.PortForward, 0, len(*portForwards))
873		for _, rule := range *portForwards {
874			if rule.Static {
875				staticPortForwards = append(staticPortForwards, rule)
876			}
877		}
878		*portForwards = staticPortForwards
879	}
880	
881	func executeGuestTemplate(format, instDir string, user limatype.User, param map[string]string) (bytes.Buffer, error) {
882		tmpl, err := template.New("").Parse(format)
883		if err == nil {
884			name := filepath.Base(instDir)
885			data := map[string]any{
886				"Name":     name,
887				"Hostname": hostname.FromInstName(name), // TODO: support customization
888				"UID":      *user.UID,
889				"User":     *user.Name,
890				"Home":     *user.Home,
891				"Param":    param,
892			}
893			var out bytes.Buffer
894			err = tmpl.Execute(&out, data)
895			if err == nil {
896				return out, nil
897			}
898		}
899		return bytes.Buffer{}, err
900	}
901	
902	func executeHostTemplate(format, instDir string, param map[string]string) (bytes.Buffer, error) {
903		tmpl, err := template.New("").Parse(format)
904		if err == nil {
905			limaHome, _ := dirnames.LimaDir()
906			globalTempDir := "/tmp"
907			if runtime.GOOS == "windows" {
908				// On Windows the global temp directory "%SystemRoot%\Temp" (normally "C:\Windows\Temp")
909				// is not writable by regular users.
910				globalTempDir = os.TempDir()
911			}
912			data := map[string]any{
913				"Dir":  instDir,
914				"Name": filepath.Base(instDir),
915				// TODO: add hostname fields for the host and the guest
916				"UID":           currentUser.Uid,
917				"User":          currentUser.Username,
918				"Home":          userHomeDir,
919				"Param":         param,
920				"GlobalTempDir": globalTempDir,
921				"TempDir":       os.TempDir(),
922	
923				"Instance": filepath.Base(instDir), // DEPRECATED, use `{{.Name}}`
924				"LimaHome": limaHome,               // DEPRECATED, use `{{.Dir}}` instead of `{{.LimaHome}}/{{.Instance}}`
925			}
926			var out bytes.Buffer
927			err = tmpl.Execute(&out, data)
928			if err == nil {
929				return out, nil
930			}
931		}
932		return bytes.Buffer{}, err
933	}
934	
935	func FillPortForwardDefaults(rule *limatype.PortForward, instDir string, user limatype.User, param map[string]string) {
936		if rule.Proto == "" {
937			rule.Proto = limatype.ProtoAny
938		}
939		if rule.GuestIP == nil {
940			if rule.GuestIPMustBeZero != nil && *rule.GuestIPMustBeZero {
941				rule.GuestIP = net.IPv4zero
942			} else {
943				rule.GuestIP = IPv4loopback1
944			}
945		}
946		if rule.GuestIPMustBeZero == nil {
947			rule.GuestIPMustBeZero = ptr.Of(rule.GuestIP.Equal(net.IPv4zero))
948		}
949		if rule.HostIP == nil {
950			rule.HostIP = IPv4loopback1
951		}
952		if rule.GuestPortRange[0] == 0 && rule.GuestPortRange[1] == 0 {
953			if rule.GuestPort == 0 {
954				rule.GuestPortRange[0] = 1
955				rule.GuestPortRange[1] = 65535
956			} else {
957				rule.GuestPortRange[0] = rule.GuestPort
958				rule.GuestPortRange[1] = rule.GuestPort
959			}
960		}
961		if rule.GuestSocket != "" {
962			if out, err := executeGuestTemplate(rule.GuestSocket, instDir, user, param); err == nil {
963				rule.GuestSocket = out.String()
964			} else {
965				logrus.WithError(err).Warnf("Couldn't process guestSocket %q as a template", rule.GuestSocket)
966			}
967		}
968		if rule.HostSocket != "" {
969			if out, err := executeHostTemplate(rule.HostSocket, instDir, param); err == nil {
970				rule.HostSocket = out.String()
971			} else {
972				logrus.WithError(err).Warnf("Couldn't process hostSocket %q as a template", rule.HostSocket)
973			}
974			if !filepath.IsAbs(rule.HostSocket) {
975				rule.HostSocket = filepath.Join(instDir, filenames.SocketDir, rule.HostSocket)
976			}
977		} else if rule.HostPortRange[0] == 0 && rule.HostPortRange[1] == 0 {
978			if rule.HostPort == 0 {
979				rule.HostPortRange = rule.GuestPortRange
980			} else {
981				rule.HostPortRange[0] = rule.HostPort
982				rule.HostPortRange[1] = rule.HostPort
983			}
984		}
985	}
986	
987	func FillCopyToHostDefaults(rule *limatype.CopyToHost, instDir string, user limatype.User, param map[string]string) {
988		if rule.GuestFile != "" {
989			if out, err := executeGuestTemplate(rule.GuestFile, instDir, user, param); err == nil {
990				rule.GuestFile = out.String()
991			} else {
992				logrus.WithError(err).Warnf("Couldn't process guest %q as a template", rule.GuestFile)
993			}
994		}
995		if rule.HostFile != "" {
996			if out, err := executeHostTemplate(rule.HostFile, instDir, param); err == nil {
997				rule.HostFile = out.String()
998			} else {
999				logrus.WithError(err).Warnf("Couldn't process host %q as a template", rule.HostFile)
1000			}
1001		}
1002	}
1003	
1004	func IsExistingInstanceDir(dir string) bool {
1005		// existence of "lima.yaml" does not signify existence of the instance,
1006		// because the file is created during the initialization of the instance.
1007		for _, f := range []string{
1008			filenames.HostAgentStdoutLog, filenames.HostAgentStderrLog,
1009			filenames.VzIdentifier, filenames.Image, filenames.Disk, filenames.BaseDiskLegacy, filenames.DiffDiskLegacy, filenames.CIDataISO,
1010		} {
1011			file := filepath.Join(dir, f)
1012			if _, err := os.Lstat(file); !errors.Is(err, os.ErrNotExist) {
1013				return true
1014			}
1015		}
1016		return false
1017	}
1018	
1019	func ResolveOS(s *string) limatype.OS {
1020		if s == nil || *s == "" || *s == "default" {
1021			return limatype.NewOS("linux")
1022		}
1023		return *s
1024	}
1025	
1026	func ResolveArch(s *string) limatype.Arch {
1027		if s == nil || *s == "" || *s == "default" {
1028			return limatype.NewArch(runtime.GOARCH)
1029		}
1030		return *s
1031	}
1032	
1033	func unique(s []string) []string {
1034		keys := make(map[string]bool)
1035		list := []string{}
1036		for _, entry := range s {
1037			if _, found := keys[entry]; !found {
1038				keys[entry] = true
1039				list = append(list, entry)
1040			}
1041		}
1042		return list
1043	}
