100		memory, err := units.RAMInBytes(*y.Memory)
101		if err == nil {
102			inst.Memory = memory
103		}
104		disk, err := units.RAMInBytes(*y.Disk)
105		if err == nil {
106			inst.Disk = disk
107		}
108		inst.AdditionalDisks = y.AdditionalDisks
109		inst.Networks = y.Networks
110	
111		// 0 out values since not configurable on WSL2
112		if inst.VMType == limatype.WSL2 {
113			inst.Memory = 0
114			inst.CPUs = 0
115			inst.Disk = 0
116		}
117	
118		protected := filepath.Join(instDir, filenames.Protected)
119		if _, err := os.Lstat(protected); !errors.Is(err, os.ErrNotExist) {
120			inst.Protected = true
121		}
122	
123		inspectStatus(ctx, instDir, inst, y)
124	
125		tmpl, err := template.New("format").Parse(y.Message)
126		if err != nil {
127			inst.Errors = append(inst.Errors, fmt.Errorf("message %q is not a valid template: %w", y.Message, err))
128			inst.Status = limatype.StatusBroken
129		} else {
130			data, err := AddGlobalFields(inst)
131			if err != nil {
132				inst.Errors = append(inst.Errors, fmt.Errorf("cannot add global fields to instance data: %w", err))
133				inst.Status = limatype.StatusBroken
134			} else {
135				data.Param = y.Param
136				var message strings.Builder
137				err = tmpl.Execute(&message, data)
138				if err != nil {
139					inst.Errors = append(inst.Errors, fmt.Errorf("cannot execute template %q: %w", y.Message, err))
140					inst.Status = limatype.StatusBroken
141				} else {
142					inst.Message = message.String()
143				}
144			}
145		}
146	
147		limaVersionFile := filepath.Join(instDir, filenames.LimaVersion)
148		if version, err := os.ReadFile(limaVersionFile); err == nil {
149			inst.LimaVersion = strings.TrimSpace(string(version))
150			if _, err = versionutil.Parse(inst.LimaVersion); err != nil {
151				logrus.Warnf("treating lima version %q from %q as very latest release", inst.LimaVersion, limaVersionFile)
152			}
153		} else if !errors.Is(err, os.ErrNotExist) {
154			inst.Errors = append(inst.Errors, err)
155		}
156		inst.Param = y.Param
157		return inst, nil
158	}
