160	func inspectStatus(ctx context.Context, instDir string, inst *limatype.Instance, y *limatype.LimaYAML) {
161		status, err := driverutil.InspectStatus(ctx, inst)
162		if err != nil {
163			inst.Status = limatype.StatusBroken
164			inst.Errors = append(inst.Errors, fmt.Errorf("failed to inspect status: %w", err))
165			return
166		}
167	
168		if status == "" {
169			inspectStatusWithPIDFiles(instDir, inst, y)
170			return
171		}
172	
173		inst.Status = status
