176	func inspectStatusWithPIDFiles(instDir string, inst *limatype.Instance, y *limatype.LimaYAML) {
177		var err error
178		inst.DriverPID, err = ReadPIDFile(filepath.Join(instDir, filenames.PIDFile(*y.VMType)))
179		if err != nil {
180			inst.Status = limatype.StatusBroken
181			inst.Errors = append(inst.Errors, err)
182		}
183	
184		if inst.Status == limatype.StatusUnknown {
185			switch {
186			case inst.HostAgentPID > 0 && inst.DriverPID > 0:
187				inst.Status = limatype.StatusRunning
188			case inst.HostAgentPID == 0 && inst.DriverPID == 0:
189				inst.Status = limatype.StatusStopped
190			case inst.HostAgentPID > 0 && inst.DriverPID == 0:
191				inst.Errors = append(inst.Errors, errors.New("host agent is running but driver is not"))
192				inst.Status = limatype.StatusBroken
193			default:
194				inst.Errors = append(inst.Errors, fmt.Errorf("%s driver is running but host agent is not", inst.VMType))
195				inst.Status = limatype.StatusBroken
196			}
197		}
