200	// ReadPIDFile returns 0 if the PID file does not exist or the process has already terminated
201	// (in which case the PID file will be removed).
202	func ReadPIDFile(path string) (int, error) {
203		b, err := os.ReadFile(path)
204		if err != nil {
205			if errors.Is(err, os.ErrNotExist) {
206				return 0, nil
207			}
208			return 0, err
209		}
210		pid, err := strconv.Atoi(strings.TrimSpace(string(b)))
211		if err != nil {
212			return 0, err
213		}
214		proc, err := os.FindProcess(pid)
215		if err != nil {
216			return 0, err
217		}
218		// os.FindProcess will only return running processes on Windows, exit early
219		if runtime.GOOS == "windows" {
220			return pid, nil
221		}
222		err = proc.Signal(syscall.Signal(0))
223		if err != nil {
224			if errors.Is(err, os.ErrProcessDone) {
225				_ = os.Remove(path)
226				return 0, nil
227			}
228			// We may not have permission to send the signal (e.g. to network daemon running as root).
229			// But if we get a permissions error, it means the process is still running.
230			if !errors.Is(err, os.ErrPermission) {
231				return 0, err
232			}
233		}
234		return pid, nil
235	}
