244			line = strings.TrimSpace(line)
245			if port, ok := strings.CutPrefix(line, "Port "); ok {
246				return strconv.Atoi(port)
247			}
248		}
249		return 0, fmt.Errorf("port not found in %q", configPath)
250	}
