254	
255		// Using these host attributes is deprecated; they will be removed in Lima 3.0
256		// The values are available from `limactl info` as hostOS, hostArch, limaHome, and identifyFile.
257		HostOS       string `json:"HostOS" yaml:"HostOS" lima:"deprecated"`
