289	type PrintOptions struct {
290		AllFields     bool
291		TerminalWidth int
292	}
293	
294	// PrintInstances prints instances in a requested format to a given io.Writer.
295	// Supported formats are "json", "yaml", "table", or a go template.
296	func PrintInstances(w io.Writer, instances []*limatype.Instance, format string, options *PrintOptions) error {
297		switch format {
298		case "json":
299			format = "{{json .}}"
300		case "yaml":
301			format = "{{yaml .}}"
302		case "table":
303			types := map[string]int{}
304			archs := map[string]int{}
305			for _, instance := range instances {
306				types[instance.VMType]++
307				archs[instance.Arch]++
308			}
309			all := options != nil && options.AllFields
310			width := 0
311			if options != nil {
312				width = options.TerminalWidth
313			}
314			columnWidth := 8
315			hideType := false
316			hideArch := false
317			hideDir := false
318	
319			columns := 1 // NAME
320			columns += 2 // STATUS
321			columns += 2 // SSH
322			// can we still fit the remaining columns (7)
323			if width == 0 || (columns+7)*columnWidth > width && !all {
324				hideType = len(types) == 1
325			}
326			if !hideType {
327				columns++ // VMTYPE
328			}
329			// only hide arch if it is the same as the host arch
330			goarch := limatype.NewArch(runtime.GOARCH)
331			// can we still fit the remaining columns (6)
332			if width == 0 || (columns+6)*columnWidth > width && !all {
333				hideArch = len(archs) == 1 && instances[0].Arch == goarch
334			}
335			if !hideArch {
336				columns++ // ARCH
337			}
338			columns++ // CPUS
339			columns++ // MEMORY
340			columns++ // DISK
341			// can we still fit the remaining columns (2)
342			if width != 0 && (columns+2)*columnWidth > width && !all {
343				hideDir = true
344			}
345			if !hideDir {
346				columns += 2 // DIR
347			}
348			_ = columns
349	
350			w := tabwriter.NewWriter(w, 4, 8, 4, ' ', 0)
351			fmt.Fprint(w, "NAME\tSTATUS\tSSH")
352			if !hideType {
353				fmt.Fprint(w, "\tVMTYPE")
354			}
355			if !hideArch {
356				fmt.Fprint(w, "\tARCH")
357			}
358			fmt.Fprint(w, "\tCPUS\tMEMORY\tDISK")
359			if !hideDir {
360				fmt.Fprint(w, "\tDIR")
361			}
362			fmt.Fprintln(w)
363	
364			homeDir, err := os.UserHomeDir()
365			if err != nil {
366				return err
367			}
368	
369			for _, instance := range instances {
370				dir := instance.Dir
371				if strings.HasPrefix(dir, homeDir) {
372					dir = strings.Replace(dir, homeDir, "~", 1)
373				}
374				fmt.Fprintf(w, "%s\t%s\t%s",
375					instance.Name,
376					instance.Status,
377					fmt.Sprintf("%s:%d", instance.SSHAddress, instance.SSHLocalPort),
378				)
379				if !hideType {
380					fmt.Fprintf(w, "\t%s",
381						instance.VMType,
382					)
383				}
384				if !hideArch {
385					fmt.Fprintf(w, "\t%s",
386						instance.Arch,
387					)
388				}
389				fmt.Fprintf(w, "\t%d\t%s\t%s",
390					instance.CPUs,
391					units.BytesSize(float64(instance.Memory)),
392					units.BytesSize(float64(instance.Disk)),
393				)
394				if !hideDir {
395					fmt.Fprintf(w, "\t%s",
396						dir,
397					)
398				}
399				fmt.Fprint(w, "\n")
400			}
401			return w.Flush()
402		default:
403			// NOP
404		}
405		tmpl, err := template.New("format").Funcs(textutil.TemplateFuncMap).Parse(format)
406		if err != nil {
407			return fmt.Errorf("invalid go template: %w", err)
408		}
409		for _, instance := range instances {
410			data, err := AddGlobalFields(instance)
411			if err != nil {
412				return err
413			}
414			data.Message = strings.TrimSuffix(instance.Message, "\n")
415			err = tmpl.Execute(w, data)
416			if err != nil {
417				return err
418			}
419			fmt.Fprintln(w)
420		}
421		return nil
422	}
