	varLog, _ := filepath.Abs("/var/log")
	d = limatype.LimaYAML{
		// Remove driver-specific VMType from defaults test
		OS:     ptr.Of("unknown"),
		Arch:   ptr.Of("unknown"),
		CPUs:   ptr.Of(7),
		Memory: ptr.Of("5GiB"),
		Disk:   ptr.Of("105GiB"),
		AdditionalDisks: []limatype.Disk{
			{Name: "data"},
		},
		GuestInstallPrefix: ptr.Of("/opt"),
		UpgradePackages:    ptr.Of(true),
		Containerd: limatype.Containerd{
