func TestYQVarModification(t *testing.T) {
	logrus.SetLevel(logrus.DebugLevel)

	// Test: Does yq modify variables even when the pipeline has no output?
	// The expression: $a | select(false) | $b = "modified" | "should not print"
	// select(false) should stop the pipeline, so $b should NOT be modified.

	documents := "{a: 1}\n---\n{b: 2}\n"

	// Verify $b starts as {b: 2}
	expr := `select(document_index == 0) as $a | select(document_index == 1) as $b | $b`
	out, _ := yqutil.EvaluateExpression(expr, []byte(documents))
	t.Logf("$b initial:\n%s===", string(out))

	// Now try: select(.nonexistent) on $a, then modify $b
	// If yq properly stops the pipeline, $b should NOT be modified
	expr = `select(document_index == 0) as $a | select(document_index == 1) as $b | $a | select(.nonexistent) | $b = "modified" | $b`
	out, _ = yqutil.EvaluateExpression(expr, []byte(documents))
	t.Logf("$b after select(.nonexistent) | $b = modified | $b:\n%s===", string(out))

	// Now try: has the same effect as the DNS delete line?
	expr = `select(document_index == 0) as $a | select(document_index == 1) as $b | $a | select(.nonexistent) | del($b.b) | $b`
	out, _ = yqutil.EvaluateExpression(expr, []byte(documents))
	t.Logf("$b after select(.nonexistent) | del($b.b) | $b:\n%s===", string(out))

	// What about with dns specifically?
	documents2 := "{}\n---\ndns: [1.1.1.1, 8.8.8.8]\n"
	expr = `select(document_index == 0) as $a | select(document_index == 1) as $b | $b as $c | $a | select(.dns) | del($b.dns, $c.dns) | $b`
	out, _ = yqutil.EvaluateExpression(expr, []byte(documents2))
	t.Logf("$b after DNS delete (dns test):\n%s===", string(out))

	// What if we add a condition that checks $a has dns using if/then?
	// Alternative approach: use a conditional
	expr = `select(document_index == 0) as $a | select(document_index == 1) as $b | $b as $c | $a | .dns | select(. != null) | del($b.dns, $c.dns) | $b`
	out, _ = yqutil.EvaluateExpression(expr, []byte(documents2))
	t.Logf("$b after .dns | select(. != null) | del($b.dns, $c.dns) | $b:\n%s===", string(out))

	// Another alternative: check if dns exists on $a differently
	expr = `select(document_index == 0) as $a | select(document_index == 1) as $b | $b as $c | $a | has("dns")`
	out, _ = yqutil.EvaluateExpression(expr, []byte(documents2))
