		},
		{
			name:     "has+dns approach",
			dnsExpr: `($a | has("dns")) as $aHasDns | $b | $aHasDns as $flag | select($flag) | del(.dns) | $c | select($flag) | del(.dns)`,
			override: true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			for _, docs := range []struct {
				name      string
				documents string
				expectDns bool
			}{
				{"template_no_dns", documents1, true},
				{"template_has_dns", documents2, false},
			} {
				expr := `select(document_index == 0) as $a | select(document_index == 1) as $b | $b as $c | ` +
					`$a | select(.base | tag == "!!seq") | del(.base[0]) | ` +
					`$a | select(.base | (tag == "!!seq" and length == 0)) | del(.base) | ` +
					`$a | select(.base | tag == "!!str") | del(.base) | ` +
